mapper.select:
select video_user_collections_item.id, collections_id, video_id, cover_url, url, description, creator_id
from video_user_collections_item
join video on video_user_collections_item.video_id = video.id
where video_user_collections_item.collections_id = #{collectionsId}

    and video_user_collections_item.id < #{lastMinId}

order by video_user_collections_item.id desc limit 15
